import 'package:equatable/equatable.dart'; enum ConnectionQuality { poor, fair, good, excellent } class ConnectionEntity extends Equatable { final String connectionId; final String localPeerId; final String remotePeerId; final ConnectionQuality quality; final double bitrateKbps; final int latencyMs; final double packetLoss; final bool isConnected; const ConnectionEntity({required this.connectionId, required this.localPeerId, required this.remotePeerId, this.quality = ConnectionQuality.fair, this.bitrateKbps = 0, this.latencyMs = 0, this.packetLoss = 0, this.isConnected = false}); @override List<Object?> get props => [connectionId, isConnected, quality]; }
